import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { DefaultMainStageHeader } from '../../../includes';
import { stockStrings } from '../config';
import { stockActions } from '../actions';


const style = theme => ({
    root: {
    }
})
class _StoreStageHeader extends Component {
    cancelEditHandler = () => {        
        stockActions.setStoreEditMode(false)(this.props.dispatch);
    }
    editBtnHandler = ( ) => {
        const {
            dispatch,
            [stockStrings.storeEditMode] : storeEditMode
        } = this.props;
        if(storeEditMode){
            //do something
        }
        stockActions.setStoreEditMode(!Boolean(storeEditMode))(dispatch);
    }
    render() {
        const {
            classes,
            [stockStrings.storeEditMode] : storeEditMode
        } = this.props;
        return (
            <DefaultMainStageHeader
                cancelEditHandler={this.cancelEditHandler.bind(this)}
                editBtnHandler={this.editBtnHandler.bind(this)}
                editMode={storeEditMode}
                />
        );
    }
}


_StoreStageHeader.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({stockReducer}) => ({
    [stockStrings.storeEditMode] : stockReducer[stockStrings.storeEditMode],
})


export const StoreStageHeader = connect(mapStateToProps)(withStyles(style)(_StoreStageHeader));
export {StoreStageHeader as default}