import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, mainStageHeaderAction, mainStageHeaderStrings, MyTable, EditableCellMapFormat, HighlightedInfo } from '../../../includes';
import { routeNamesInventory } from '../../routeNames';
import StoreStageHeader from './StoreStageHeader';
import { stockStrings } from '../config';
import { stockActions } from '../actions';


const style = theme => ({
    root: {
        marginTop : 20
    }
})
class _Stores extends Component {
    constructor(props) {
        super(props);
        this.state = {
            stores : null,
            storesUnusable : null
        }
        const { dispatch} = props;

        headerActions({
            [headerStrings.headerTitle] : "STORES"
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesInventory.dashboard},
            {name : "Stores", path : routeNamesInventory.stockStores},
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                StoreStageHeader
            ]
        })(dispatch);
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {
            dispatch 
        } = this.props;
        stockActions.getStores()(dispatch);
    }
    static getDerivedStateFromProps(props, state) {
        const {stores} = props;
        if(!state.storesUnusable && stores){
            state.storesUnusable = state.stores = stores;
        }else if(JSON.stringify(state.storesUnusable) !==
        JSON.stringify(stores)){
            state.storesUnusable = state.stores = stores;
        }
        return state;
    }
    cellMapFormat = superProps => props => <EditableCellMapFormat {...props} {...superProps}/>
    render() {
        const {
            classes,
            [stockStrings.storeEditMode] : editMode
        } = this.props;
        let {stores} = this.state;
        let header = ["ID", "Name", "Description"];
        let dataMap = ["_id", "name", "description"];
        if(editMode){
            header = [...header, "Actions"];
            dataMap = [...dataMap, "action"];
            stores = stores ? 
                [...stores.map(item=>({...item, editable : true, delible: true})), {new : true}] :
                [{new : true}];
        }
        return (
            <div className={classes.root}>
                {editMode && <HighlightedInfo closable>
                    To edit or add the address of the store, click on done and address dialog will appear as the next phase.
                </HighlightedInfo>}
                <MyTable
                    header={header}
                    dataMap={dataMap}
                    data={stores}
                    CellMap={this.cellMapFormat({
                        skipEdit : ["_id"]
                    })}
                    />
            </div>
        );
    }
}


_Stores.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({stockReducer}) => ({
    [stockStrings.stores] : stockReducer[stockStrings.stores],
    [stockStrings.storeEditMode] : stockReducer[stockStrings.storeEditMode],
})


export const Stores = connect(mapStateToProps)(withStyles(style)(_Stores));
export {Stores as default}